#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        shadow[tx * BLOCK_SIZE + j] =
            m[(offset + tx) * matrix_dim + (offset + j)];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if (tx > i) {
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            float l = shadow[tx * BLOCK_SIZE + i];
            for (int j = i + 1; j < BLOCK_SIZE; j++) {
                shadow[tx * BLOCK_SIZE + j] -=
                    l * shadow[i * BLOCK_SIZE + j];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int j = 0; j < BLOCK_SIZE; j++) {
        m[(offset + tx) * matrix_dim + (offset + j)] =
            shadow[tx * BLOCK_SIZE + j];
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int bx = (int)get_group_id(0);
    int global_offset = offset + BLOCK_SIZE * (bx + 1);

    if (tx < BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            dia[tx * BLOCK_SIZE + j] =
                m[(offset + tx) * matrix_dim + (offset + j)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            peri_row[i * BLOCK_SIZE + tx] =
                m[(offset + i) * matrix_dim + (global_offset + tx)];
        }

        for (int i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += dia[i * BLOCK_SIZE + k] *
                       peri_row[k * BLOCK_SIZE + tx];
            }
            peri_row[i * BLOCK_SIZE + tx] -= sum;
        }

        for (int i = 0; i < BLOCK_SIZE; i++) {
            m[(offset + i) * matrix_dim + (global_offset + tx)] =
                peri_row[i * BLOCK_SIZE + tx];
        }
    } else {
        int ty = tx - BLOCK_SIZE;

        for (int j = 0; j < BLOCK_SIZE; j++) {
            peri_col[ty * BLOCK_SIZE + j] =
                m[(global_offset + ty) * matrix_dim + (offset + j)];
        }

        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += peri_col[ty * BLOCK_SIZE + k] *
                       dia[k * BLOCK_SIZE + j];
            }
            peri_col[ty * BLOCK_SIZE + j] =
                (peri_col[ty * BLOCK_SIZE + j] - sum) /
                dia[j * BLOCK_SIZE + j];
        }

        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[(global_offset + ty) * matrix_dim + (offset + j)] =
                peri_col[ty * BLOCK_SIZE + j];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);
    int ty = (int)get_local_id(1);
    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);

    int global_col = offset + BLOCK_SIZE * (bx + 1);
    int global_row = offset + BLOCK_SIZE * (by + 1);

    peri_row[ty * BLOCK_SIZE + tx] =
        m[(offset + ty) * matrix_dim + (global_col + tx)];
    peri_col[ty * BLOCK_SIZE + tx] =
        m[(global_row + ty) * matrix_dim + (offset + tx)];

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += peri_col[ty * BLOCK_SIZE + k] *
               peri_row[k * BLOCK_SIZE + tx];
    }

    m[(global_row + ty) * matrix_dim + (global_col + tx)] -= sum;
}
